package com.evolua.social.infrastructure.persistence; import com.evolua.social.domain.Post; import com.evolua.social.domain.PostRepository; import java.util.List; import org.springframework.stereotype.Repository; @Repository public class PostPersistenceAdapter implements PostRepository { private final PostMongoRepository repository; public PostPersistenceAdapter(PostMongoRepository repository) { this.repository = repository; } public Post save(Post item) { PostDocument document = new PostDocument(); document.setId(item.id()); document.setUserId(item.userId()); document.setContent(item.content()); document.setCommunity(item.community()); document.setVisibility(item.visibility()); document.setCreatedAt(item.createdAt()); PostDocument saved = repository.save(document); return new Post(saved.getId(), saved.getUserId(), saved.getContent(), saved.getCommunity(), saved.getVisibility(), saved.getCreatedAt()); } public List<Post> findAllByUserId(String userId) { return repository.findAllByUserId(userId).stream().map(saved -> new Post(saved.getId(), saved.getUserId(), saved.getContent(), saved.getCommunity(), saved.getVisibility(), saved.getCreatedAt())).toList(); } }
